import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/launcher-screen.B4Y3DSWp.js";const o=JSON.parse(`{"title":"Windows에 Fabric 설치하기","description":"Windows에 Fabric을 설치하기 위한 단계별 가이드","frontmatter":{"title":"Windows에 Fabric 설치하기","description":"Windows에 Fabric을 설치하기 위한 단계별 가이드","authors":["Benonardo","ezfe","IMB11","modmuss50"],"next":false,"files":[]},"headers":[],"relativePath":"ko_kr/players/installing-fabric/windows.md","filePath":"translated/ko_kr/players/installing-fabric/windows.md","lastUpdated":1772272927000}`);var s={name:`ko_kr/players/installing-fabric/windows.md`};function c(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Windows에 Fabric 설치하기 <a class="header-anchor" href="#h1" aria-label="Permalink to “Windows에 Fabric 설치하기”">​</a></h1><h2 id="1-download-the-fabric-installer" tabindex="-1">1. Fabric 설치기 다운로드 <a class="header-anchor" href="#1-download-the-fabric-installer" aria-label="Permalink to “1. Fabric 설치기 다운로드”">​</a></h2><p>Fabric 설치기를 <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">Fabric 웹사이트</a>에 접속한 후, <code>윈도우용 설치기 다운로드</code> 버튼을 눌러 다운로드하세요. 다운로드하려는 파일 형식은 <code>.exe</code> 입니다.</p><div class="tip custom-block"><p class="custom-block-title custom-block-title-default">TIP</p><p>공식 마인크래프트 런처에 Java가 내장되어 있기 때문에<code>.exe</code> 형식의 설치기는 Java가 필요하지 않습니다.</p></div><h2 id="2-run-the-fabric-installer" tabindex="-1">2. Fabric 설치기 시작 <a class="header-anchor" href="#2-run-the-fabric-installer" aria-label="Permalink to “2. Fabric 설치기 시작”">​</a></h2><p>설치기를 시작하기 전에, 먼저 모든 Minecraft 인스턴스와 Minecrft 런처를 종료해야 합니다.</p><p>설치기를 실행하면, 아래 사진과 같이 실행됩니다:</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="&quot;Install&quot;을 강조 표시한 Fabric 설치기" loading="lazy"></p><p>원하는 마인크래프트 버전을 선택하고 설치합니다. <code>프로필 생성</code>이 켜져 있는지 확인하세요.</p><h2 id="3-finish-setup" tabindex="-1">3. 마무리 <a class="header-anchor" href="#3-finish-setup" aria-label="Permalink to “3. 마무리”">​</a></h2><p>설치가 끝나면, 마인크래프트 런처를 실행하세요. 그리고 버전 선택 목록에서 Fabric 프로필을 선택하고 플레이 버튼을 누르새요.</p><p><img src="/assets/players/installing-fabric/launcher-screen.png" alt="Fabric 프로필이 선택된 Minecraft 런처" loading="lazy"></p><p>이제 게임에 모드를 적용할 수 있습니다. <a href="./../finding-mods">안전한 모드 탐색</a>에서 자세한 정보를 확인해보세요.</p><p>문제가 발생했다면, 자유롭게 <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Fabric 디스코드(영어)</a>의 <code>#player-support</code> 채널에서 도움을 요청할 수 있습니다.</p>`,14)]])}var l=r(s,[[`render`,c]]);export{o as __pageData,l as default};